const d = $input.first().json;
const now = new Date();
const citaFecha = d.fechaTimestamp ? new Date(d.fechaTimestamp) : new Date();
const diffMs = citaFecha - now;
const diffHoras = diffMs / (1000 * 60 * 60);
// Enviar 72h antes; si queda menos de 72h, enviar en 30 min
const esperarMs = diffHoras > 72
  ? diffMs - 72 * 60 * 60 * 1000
  : Math.max(30 * 60 * 1000, diffMs - 2 * 60 * 60 * 1000);
return [{ json: { ...d, esperarMs: Math.max(0, esperarMs) } }];

const d = $input.first().json;
const esMenor = d.esMenor || false;
const telefonoDestino = esMenor && d.telefonoTutor ? d.telefonoTutor : d.telefono;
const linkCuestionario = `${$vars.CUESTIONARIO_BASE_URL}?token=${d.token || d.idPac}`;
const destinatario = esMenor ? (d.nombreTutor || d.nombre) : d.nombre;
const msg = `📋 ¡Bienvenido/a a ${$vars.CLINICA_NOMBRE}${esMenor ? ` — para ${d.nombre}` : ''}, ${destinatario}!\n\nAntes de tu primera cita el *${d.fechaStr}*, completa este cuestionario de salud en 3-5 minutos:\n👉 ${linkCuestionario}\n\n⏰ El enlace expira 1h tras tu cita. ¿Dudas? 📞 ${$vars.CLINICA_TELEFONO}`;
return [{ json: { ...d, mensaje: msg, telefonoDestino, linkCuestionario } }];
